using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainerService>();

var app = builder.Build();

// Train the model at startup and log evaluation metrics
var trainer = app.Services.GetRequiredService<ModelTrainerService>();
trainer.TrainAndEvaluate();

// Register the pooled prediction engine with the trained model
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.GetModelPath());

// Rebuild the service provider to include the prediction engine pool
app = builder.Build();

app.MapControllers();
app.Run();

